  0%, 100% {
    box-shadow:
      0 0 5px var(--juku-neon-cyan),
      0 0 10px var(--juku-neon-cyan),
      inset 0 0 5px oklch(0.85 0.18 195 / 0.1);
  }
  50% {
    box-shadow:
      0 0 15px var(--juku-neon-cyan),
      0 0 40px var(--juku-neon-cyan),
      0 0 80px oklch(0.85 0.18 195 / 0.4),
      inset 0 0 10px oklch(0.85 0.18 195 / 0.2);
  }
}

@keyframes juku-scan {
  0% { transform: translateY(-100%); }
  100% { transform: translateY(100vh); }
}

@keyframes juku-border-flow {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

.juku-neon-text-cyan {
  text-shadow:
    0 0 7px var(--juku-neon-cyan),
    0 0 21px var(--juku-neon-cyan),
    0 0 42px var(--juku-neon-cyan);
}

.juku-neon-text-magenta {
  text-shadow:
    0 0 7px var(--juku-neon-magenta),
    0 0 21px var(--juku-neon-magenta);
}

.juku-neon-text-gold {
  text-shadow:
    0 0 7px var(--juku-neon-gold),
    0 0 21px var(--juku-neon-gold);
}

.juku-neon-text-green {
  text-shadow:
    0 0 7px var(--juku-neon-green),
    0 0 21px var(--juku-neon-green);
}

.juku-glass {
  background: var(--juku-surface);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid oklch(1 0 0 / 0.08);
}

.juku-grid-bg {
  background-image:
    linear-gradient(var(--juku-grid) 1px, transparent 1px),
    linear-gradient(90deg, var(--juku-grid) 1px, transparent 1px);
  background-size: 48px 48px;
}

.juku-record-spin {
  animation: juku-record-spin 24s linear infinite;
}

.juku-float {
  animation: juku-float 5s ease-in-out infinite;
}

.juku-neon-pulse {
  animation: juku-neon-pulse 3s ease-in-out infinite;
}

.juku-glow-border {
  animation: juku-glow-expand 3s ease-in-out infinite;
}

.juku-scanline::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    oklch(0 0 0 / 0.04) 2px,
    oklch(0 0 0 / 0.04) 4px
  );
  pointer-events: none;
  z-index: 1;
}

.juku-cta-btn-primary {
  position: relative;
  background: transparent;
  border: 1px solid var(--juku-neon-cyan);
  color: var(--juku-neon-cyan);
  transition: all 0.3s ease;
  overflow: hidden;
}

.juku-cta-btn-primary::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--juku-neon-cyan);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.3s ease;
  z-index: 0;
}

.juku-cta-btn-primary:hover::before {
  transform: scaleX(1);
}

.juku-cta-btn-primary:hover {
  color: var(--juku-bg);
  box-shadow: 0 0 20px var(--juku-neon-cyan), 0 0 40px oklch(0.85 0.18 195 / 0.3);
}

.juku-cta-btn-primary span {
  position: relative;
  z-index: 1;
}

.juku-cta-btn-secondary {
  position: relative;
  background: transparent;
  border: 1px solid oklch(1 0 0 / 0.3);
  color: oklch(0.85 0 0);
  transition: all 0.3s ease;
}

.juku-cta-btn-secondary:hover {
  border-color: oklch(1 0 0 / 0.6);
  color: white;
}

.juku-feature-card {
  position: relative;
  overflow: hidden;
  transition: all 0.4s ease;
}

.juku-feature-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--juku-card-accent, var(--juku-neon-cyan)), transparent);
  opacity: 0.8;
}

.juku-feature-card:hover {
  transform: translateY(-4px);
  border-color: oklch(1 0 0 / 0.15);
}

.juku-step-connector {
  position: relative;
}

.juku-step-connector::after {
  content: '';
  position: absolute;
  top: 24px;
  left: 100%;
  width: 100%;
  height: 1px;
  background: linear-gradient(90deg, var(--juku-neon-cyan), transparent);
  opacity: 0.3;
}

